      "author": "** [[titus-jr-laxa]]",
      "source": "** raw/notes/AI and the Christian Life.md (voice memo transcription)",
      "coverImage": "https://images.unsplash.com/photo-5e4Zlblkvks?q=80&w=1200&auto=format&fit=crop",
