      "wordCount": 375,
      "readTime": 2,
      "author": "Titus Jr. Laxa",
      "source": null,
      "coverImage": "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?q=80&w=1200&auto=format&fit=crop",
